mapper.select:
SELECT A.COM_CD_ID /* 공통코드아이디 */ , A.COM_CD_NM /* 공동코드명 */ , B.DTL_CD_ID /* 상세코드아이디 */ , B.DTL_CD_NM /* 상세코드명 */ , B.DTL_CD_EXPLN /* 상세코드설명 */ , B.LNKG_DTL_CD_ID1 /* 연결상세코드아이디1 */ , B.LNKG_DTL_CD_NM1 /* 연결상세코드명1 */ , B.LNKG_DTL_CD_ID2 /* 연결상세코드아이디2 */ , B.LNKG_DTL_CD_NM2 /* 연결상세코드명2 */ FROM CMM_CODE A INNER JOIN CMM_CODE_DTL B ON A.COM_CD_ID = B.COM_CD_ID WHERE A.COM_CD_ID = #{comCdId}
AND B.DTL_CD_ID = #{dtlCdId}
AND A.USE_YN = 'Y' ORDER BY SORT_SEQ
